class SurveyController {
  constructor() {
    this.currentPart = 1;
    this.totalParts = 4;
    this.responses = {};
    this.isSubmitting = false;
  }

  nextPart() {
    if (this.validateCurrentPart()) {
      this.saveCurrentResponses();
      this.currentPart++;
      this.updateProgressBar();
      this.renderCurrentPart();
    }
  }

  previousPart() {
    if (this.currentPart > 1) {
      this.currentPart--;
      this.updateProgressBar();
      this.renderCurrentPart();
    }
  }

  updateProgressBar() {
    const progress = (this.currentPart / this.totalParts) * 100;
    document.querySelector('.progress-fill').style.width = `${progress}%`;
  }
}
```

