class ValidationSystem {
  static validateRadio(questionId, value) {
    if (!value) {
      return { valid: false, message: '선택지를 선택해주세요.' };
    }
    return { valid: true };
  }

  static validateNumber(questionId, value) {
    if (!value || isNaN(value) || value < 0) {
      return { valid: false, message: '올바른 숫자를 입력해주세요.' };
    }
    return { valid: true };
  }

  static validateEmail(value) {
    if (!value) return { valid: true }; // 선택사항
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(value)) {
      return { valid: false, message: '올바른 이메일 형식을 입력해주세요.' };
    }
