```javascript
class QRGenerator {
  constructor() {
    this.qrCode = null;
  }

  generateQR(url) {
    const qrContainer = document.getElementById('qr-display');
    this.qrCode = new QRCode(qrContainer, {
      text: url,
      width: 300,
      height: 300,
      colorDark: '#0A0A0F',
      colorLight: '#FFFFFF'
    });
  }

  downloadQR() {
    const canvas = document.querySelector('#qr-display canvas');
    const link = document.createElement('a');
    link.download = 'mastermind-survey-qr.png';
    link.href = canvas.toDataURL();
    link.click();
  }
}
```
